1	<?php
2	declare(strict_types=1);
3	
4	namespace app\service;
5	
6	use app\domain\bookings\BookingDomainPolicy;
7	use app\exception\ConflictException;
8	use app\exception\NotFoundException;
9	use app\exception\ValidationException;
10	use app\repository\BookingRepository;
11	use think\facade\Db;
12	
13	final class BookingService
14	{
15	    public function __construct(
16	        private readonly BookingRepository $bookingRepository,
17	        private readonly BookingDomainPolicy $bookingDomainPolicy
18	    )
19	    {
20	    }
21	
22	    public function list(array $scopes = [], array $authUser = [], int $page = 1, int $perPage = 20): array
23	    {
24	        return $this->bookingRepository->list($scopes, $authUser, $page, $perPage);
25	    }
26	
27	    public function create(array $payload): array
28	    {
29	        $this->bookingDomainPolicy->assertFuturePickup($payload['pickup_at']);
30	
31	        $pickupAtTs = strtotime($payload['pickup_at']);
32	        if ($pickupAtTs === false) {
33	            throw new \InvalidArgumentException('Invalid pickup_at');
34	        }
35	
36	        if ($pickupAtTs > strtotime('+7 days')) {
37	            throw new ValidationException('Booking can only be made up to 7 days ahead');
38	        }
39	
40	        if ($pickupAtTs - time() < 7200) {
41	            throw new ValidationException('Booking cutoff is 2 hours before pickup');
42	        }
43	
44	        $blacklist = $this->bookingRepository->activeBlacklist((int) $payload['user_id']);
45	        if ($blacklist) {
46	            throw new ValidationException('User is temporarily blacklisted due to repeated no-show');
47	        }
48	
49	        $zip4 = (string) ($payload['customer_zip4'] ?? '');
50	        if ($zip4 !== '' && !preg_match('/^\d{5}-\d{4}$/', $zip4)) {
51	            throw new ValidationException('ZIP+4 must be in format 12345-6789');
52	        }
53	
54	        $regionCode = (string) ($payload['customer_region_code'] ?? '');
55	        if ($regionCode !== '' && !$this->bookingRepository->regionExists($regionCode)) {
56	            throw new ValidationException('Invalid admin region');
57	        }
58	
59	        if ($zip4 !== '' && $regionCode !== '' && !$this->bookingRepository->zip4InRegion($zip4, $regionCode)) {
60	            throw new ValidationException('ZIP+4 does not match admin region');
61	        }
62	
63	        $slotStart = (string) ($payload['slot_start'] ?? $payload['pickup_at']);
64	        $slotEnd = (string) ($payload['slot_end'] ?? date('Y-m-d H:i:s', strtotime($slotStart) + 1800));
65	        $point = $this->bookingRepository->pickupPointById((int) $payload['pickup_point_id']);
66	        if (!$point) {
67	            throw new NotFoundException('Pickup point not found');
68	        }
69	
70	        $qty = (int) ($payload['quantity'] ?? 1);
71	
72	        if (!empty($payload['customer_latitude']) && !empty($payload['customer_longitude'])
73	            && !empty($point['latitude']) && !empty($point['longitude'])) {
74	            $distance = $this->haversine(
75	                (float) $payload['customer_latitude'],
76	                (float) $payload['customer_longitude'],
77	                (float) $point['latitude'],
78	                (float) $point['longitude']
79	            );
80	
81	            if ($distance > (float) ($point['service_radius_km'] ?? 0)) {
82	                throw new ValidationException('Address is outside service radius');
83	            }
84	            $payload['distance_km'] = round($distance, 3);
85	        }
86	
87	        $payload['slot_start'] = $slotStart;
88	        $payload['slot_end'] = $slotEnd;
89	        $payload['booking_code'] = $payload['booking_code'] ?? 'BKG-' . strtoupper(bin2hex(random_bytes(3)));
90	
91	        try {
92	            $id = Db::transaction(function () use ($point, $slotStart, $slotEnd, $qty, $payload): int {
93	                $this->bookingRepository->ensureSlot((int) $point['id'], $slotStart, $slotEnd, (int) ($point['slot_size'] ?? 0));
94	                $this->bookingRepository->reserveSlotAtomic((int) $point['id'], $slotStart, $slotEnd, $qty);
95	                return $this->bookingRepository->create($payload);
96	            });
97	        } catch (\Throwable $e) {
98	            if (str_contains($e->getMessage(), 'Slot capacity is not enough') || str_contains($e->getMessage(), 'Duplicate entry')) {
99	                throw new ConflictException(str_contains($e->getMessage(), 'Slot capacity is not enough') ? 'Slot capacity is not enough' : 'Duplicate entry', $e);
100	            }
101	            if (str_contains($e->getMessage(), 'Slot not found')) {
102	                throw new NotFoundException('Slot not found', $e);
103	            }
104	            throw $e;
105	        }
106	        $remaining = $this->bookingRepository->slotCapacity((int) $point['id'], $slotStart, $slotEnd);
107	        return ['id' => $id, 'booking_code' => $payload['booking_code'], 'slot_remaining' => $remaining['remaining']];
108	    }
109	
110	    public function pickupPoints(): array
111	    {
112	        return $this->bookingRepository->pickupPoints();
113	    }
114	
