170	    private function haversine(float $lat1, float $lon1, float $lat2, float $lon2): float
171	    {
172	        $earthRadius = 6371.0;
173	        $dLat = deg2rad($lat2 - $lat1);
174	        $dLon = deg2rad($lon2 - $lon1);
175	        $a = sin($dLat / 2) * sin($dLat / 2)
176	            + cos(deg2rad($lat1)) * cos(deg2rad($lat2)) * sin($dLon / 2) * sin($dLon / 2);
177	        $c = 2 * atan2(sqrt($a), sqrt(1 - $a));
178	        return $earthRadius * $c;
179	    }
180	}
