95	    public function processGatewayCallback(array $payload, string $signature): array
96	    {
97	        $orderRef = (string) ($payload['order_ref'] ?? '');
98	        $transactionRef = (string) ($payload['transaction_ref'] ?? '');
99	        if ($orderRef === '' || $transactionRef === '') {
100	            throw new ValidationException('order_ref and transaction_ref are required');
101	        }
102	
103	        $verified = $this->verifyGatewaySignature($payload, $signature);
104	        if (!$verified) {
105	            throw new ValidationException('Invalid callback signature');
106	        }
107	
108	        $result = Db::transaction(function () use ($orderRef, $transactionRef, $payload): array {
109	            $inserted = $this->paymentRepository->saveCallback($transactionRef, $payload);
110	            if (!$inserted) {
111	                return ['idempotent' => true, 'processed' => true];
112	            }
113	
114	            $order = $this->paymentRepository->gatewayOrderByRef($orderRef);
115	            if (!$order) {
116	                throw new NotFoundException('Gateway order not found');
117	            }
118	
119	            if ((string) ($order['status'] ?? '') === 'paid') {
120	                return ['idempotent' => true, 'processed' => true, 'booking_id' => (int) ($order['booking_id'] ?? 0)];
121	            }
122	
123	            $this->paymentRepository->markGatewayOrderPaid($orderRef, $transactionRef, $payload, true);
124	
125	            $this->create([
126	                'booking_id' => (int) $order['booking_id'],
127	                'amount' => (float) $order['amount'],
128	                'method' => 'wechat_local',
129	                'status' => 'captured',
130	            ]);
131	
132	            return ['processed' => true, 'verified' => true, 'booking_id' => (int) $order['booking_id']];
133	        });
134	
135	        if (($result['idempotent'] ?? false) === true) {
136	            Log::info('payments.gateway_callback.idempotent', ['order_ref' => $orderRef, 'transaction_ref' => $transactionRef]);
137	            return $result;
138	        }
139	
140	        Log::info('payments.gateway_callback.processed', ['order_ref' => $orderRef, 'transaction_ref' => $transactionRef, 'booking_id' => (int) ($result['booking_id'] ?? 0)]);
141	
142	        return $result;
143	    }
