145	    public function dailyReconciliation(string $date): array
146	    {
147	        $gatewayOrders = $this->paymentRepository->paidGatewayOrdersByDate($date);
148	        $payments = $this->paymentRepository->paymentsByDate($date);
149	        $paymentMap = [];
150	        foreach ($payments as $p) {
151	            $paymentMap[(int) $p['booking_id']] = true;
152	        }
153	
154	        $batchRef = 'DREC-' . date('Ymd') . '-' . strtoupper(bin2hex(random_bytes(2)));
155	        $issues = 0;
156	        $expected = 0.0;
157	        $actual = 0.0;
158	
159	        foreach ($gatewayOrders as $order) {
160	            $expected += (float) $order['amount'];
161	            if (isset($paymentMap[(int) $order['booking_id']])) {
162	                $actual += (float) $order['amount'];
163	            } else {
164	                $issues++;
165	                $this->paymentRepository->addReconciliationIssue([
166	                    'batch_ref' => $batchRef,
167	                    'gateway_order_ref' => $order['order_ref'],
168	                    'issue_type' => 'missed_order',
169	                ]);
170	            }
171	        }
172	
173	        $rec = $this->reconcile([
174	            'batch_ref' => $batchRef,
175	            'period_start' => $date,
176	            'period_end' => $date,
177	            'expected_total' => $expected,
178	            'actual_total' => $actual,
179	            'status' => $issues > 0 ? 'abnormal' : 'open',
180	        ]);
181	
182	        Log::info('payments.daily_reconciliation.completed', ['date' => $date, 'batch_ref' => $rec['batch_ref'], 'issues' => $issues, 'variance' => $rec['variance']]);
183	
184	        return ['batch_ref' => $rec['batch_ref'], 'issues' => $issues, 'variance' => $rec['variance']];
185	    }
