261	    private function verifyGatewaySignature(array $payload, string $signature): bool
262	    {
263	        ksort($payload);
264	        $message = json_encode($payload, JSON_UNESCAPED_UNICODE);
265	        $secret = (string) Config::get('security.gateway.hmac_secret');
266	        $expected = hash_hmac('sha256', (string) $message, $secret);
267	        return hash_equals($expected, $signature);
268	    }
