213	    private function assertManageableTarget(array $targetUser, array $actorUser, array $actorScopes): void
214	    {
215	        $actorId = (int) ($actorUser['id'] ?? 0);
216	        $targetId = (int) ($targetUser['id'] ?? 0);
217	        if ($actorId < 1 || $targetId < 1) {
218	            throw new ForbiddenException('Forbidden');
219	        }
220	        if ($targetId === $actorId) {
221	            throw new ValidationException('Self-management is not allowed for this action');
222	        }
223	        if ($this->isGlobalActor($actorUser)) {
224	            return;
225	        }
226	
227	        if ((string) ($targetUser['role'] ?? '') === 'admin') {
228	            throw new ForbiddenException('Forbidden');
229	        }
230	
231	        foreach (['store', 'warehouse', 'department'] as $scopeType) {
232	            $allowed = array_map('strval', $actorScopes[$scopeType] ?? []);
233	            $field = $scopeType . '_id';
234	            $targetValue = (string) ($targetUser[$field] ?? '');
235	            if ($targetValue !== '' && $allowed !== [] && !in_array($targetValue, $allowed, true)) {
236	                throw new ForbiddenException('Forbidden');
237	            }
238	        }
239	    }
240	
241	    private function normalizeScopeValues(array|string $values): array
242	    {
243	        if (is_string($values)) {
244	            $values = preg_split('/[\s,]+/', trim($values)) ?: [];
245	        }
246	
247	        $normalized = [];
248	        foreach ($values as $value) {
249	            $value = trim((string) $value);
250	            if ($value === '') {
251	                continue;
252	            }
253	            $normalized[] = $value;
254	        }
255	        return array_values(array_unique($normalized));
256	    }
257	
258	    private function assertScopeReferencesExist(array $scopeMap): void
259	    {
260	        $ref = [
261	            'store' => ['table' => 'stores', 'column' => 'id'],
262	            'warehouse' => ['table' => 'warehouses', 'column' => 'id'],
263	            'department' => ['table' => 'departments', 'column' => 'id'],
264	        ];
265	
266	        foreach ($ref as $scopeType => $meta) {
267	            $values = $scopeMap[$scopeType] ?? [];
268	            if ($values === []) {
269	                continue;
270	            }
271	            $existing = Db::name($meta['table'])->whereIn($meta['column'], $values)->column($meta['column']);
272	            $existingSet = array_map('strval', $existing);
273	            foreach ($values as $value) {
274	                if (!in_array((string) $value, $existingSet, true)) {
275	                    throw new ValidationException($scopeType . ' scope value not found: ' . $value);
276	                }
277	            }
278	        }
279	    }
280	}
