227	async function apiRequest(path, method = "GET", body = null) {
228	  const headers = { "Content-Type": "application/json" };
229	  const token = getToken();
230	  if (token) headers.Authorization = `Bearer ${token}`;
231	
232	  try {
233	    const response = await fetch(`${API_BASE}${path}`, {
234	      method,
235	      headers,
236	      body: body ? JSON.stringify(body) : null
237	    });
238	    const raw = await response.text();
239	    let data;
240	    try {
241	      data = JSON.parse(raw);
242	    } catch {
243	      const contentType = response.headers.get("content-type") || "unknown";
244	      const snippet = raw.replace(/\s+/g, " ").trim().slice(0, 220) || "(empty response body)";
245	      throw new Error(`Invalid JSON from ${method} ${path} (HTTP ${response.status}, content-type: ${contentType}). Body preview: ${snippet}`);
246	    }
247	
248	    if (!data || typeof data !== "object" || Array.isArray(data)) {
249	      throw new Error(`Invalid API payload shape from ${method} ${path}`);
250	    }
251	
252	    if (!response.ok || !data.success) throw new Error(data.message || `Request failed (HTTP ${response.status})`);
253	    return data.data;
254	  } catch (err) {
255	    if (method !== "GET" && body) {
256	      const queue = getQueue();
257	      queue.push({ path, method, body, at: Date.now() });
258	      setQueue(queue);
259	    }
260	    throw err;
261	  }
262	}
