414	async function loadSlotPicker() {
415	  const picker = document.getElementById("slotPicker");
416	  const pickupPointId = resolvePickupPointId();
417	  const dateRaw = inputValue("slotDate");
418	  if (!dateRaw) throw new Error("slotDate is required");
419	  const [year, month, day] = dateRaw.split("-").map((v) => Number(v));
420	  const startRaw = inputValue("slotWindowStart");
421	  const endRaw = inputValue("slotWindowEnd");
422	  if (!startRaw || !endRaw) throw new Error("slotWindowStart and slotWindowEnd are required");
423	  const stepMinutes = Number(inputValue("slotStepMinutes"));
424	  if (!Number.isFinite(stepMinutes) || stepMinutes < 15) throw new Error("slotStepMinutes must be >= 15");
425	
426	  const [sh, sm] = startRaw.split(":").map((v) => Number(v));
427	  const [eh, em] = endRaw.split(":").map((v) => Number(v));
428	  const startMin = sh * 60 + sm;
429	  const endMin = eh * 60 + em;
430	  if (endMin <= startMin) throw new Error("slot window end must be later than start");
431	
432	  const cards = [];
433	  for (let cursor = startMin; cursor + stepMinutes <= endMin; cursor += stepMinutes) {
434	    const start = new Date(year, month - 1, day, 0, 0, 0, 0);
435	    start.setMinutes(cursor);
436	    const end = new Date(start.getTime() + stepMinutes * 60 * 1000);
437	    const slotStart = start.toISOString().slice(0, 19).replace("T", " ");
438	    const slotEnd = end.toISOString().slice(0, 19).replace("T", " ");
439	    try {
440	      const cap = await apiRequest(`/bookings/slot-capacity?pickup_point_id=${pickupPointId}&slot_start=${encodeURIComponent(slotStart)}&slot_end=${encodeURIComponent(slotEnd)}`);
441	      cards.push({ slotStart, slotEnd, remaining: Number(cap.remaining || 0), capacity: Number(cap.capacity || 0) });
442	    } catch {
443	      cards.push({ slotStart, slotEnd, remaining: -1, capacity: -1 });
444	    }
445	  }
446	
447	  if (!cards.length) throw new Error("No slots generated. Adjust slot window and step.");
448	
449	  picker.innerHTML = cards.map((slot, idx) => `
450	    <button class="slot-card ${slot.remaining <= 0 ? "disabled" : ""}" data-idx="${idx}" ${slot.remaining <= 0 ? "disabled" : ""}>
451	      <strong>${slot.slotStart.slice(11, 16)} - ${slot.slotEnd.slice(11, 16)}</strong>
452	      <span>${slot.remaining >= 0 ? `${slot.remaining}/${slot.capacity} remaining` : "Unavailable"}</span>
453	    </button>
454	  `).join("");
455	
456	  picker.querySelectorAll(".slot-card").forEach((btn) => {
457	    btn.addEventListener("click", () => {
458	      picker.querySelectorAll(".slot-card").forEach((x) => x.classList.remove("active"));
459	      btn.classList.add("active");
460	      selectedSlot = cards[Number(btn.dataset.idx || "0")];
461	      setFeedback("bookingFeedback", { selected_recipe_id: selectedRecipeId, pickup_point_id: pickupPointId, selected_slot: selectedSlot });
462	    });
463	  });
464	}
