49	    public function sendMessage(array $payload, array $scopes = [], array $authUser = []): array
50	    {
51	        $userId = (int) ($payload['user_id'] ?? 0);
52	        if ($userId < 1) {
53	            throw new \InvalidArgumentException('user_id is required');
54	        }
55	
56	        $recipient = Db::name('users')->where('id', $userId)->field('id,store_id,warehouse_id,department_id')->find();
57	        if (!$recipient) {
58	            throw new \RuntimeException('Recipient not found');
59	        }
60	
61	        if ((string) ($authUser['role'] ?? '') !== 'admin' && !$this->recipientInScope($recipient, $scopes, $authUser)) {
62	            throw new ForbiddenException('Forbidden');
63	        }
64	
65	        $isMarketing = (bool) ($payload['is_marketing'] ?? false);
66	        if ($isMarketing) {
67	            $pref = Db::name('user_message_preferences')->where('user_id', $userId)->find();
68	            if ($pref && (int) $pref['marketing_opt_out'] === 1) {
69	                throw new \RuntimeException('User opted out of marketing messages');
70	            }
71	
72	            $cap = (int) Config::get('security.messaging.daily_marketing_cap', 2);
73	            $countToday = Db::name('message_center')
74	                ->where('user_id', $userId)
75	                ->where('is_marketing', 1)
76	                ->whereDay('sent_at', $this->todayString())
77	                ->count();
78	            if ($countToday >= $cap) {
79	                throw new \RuntimeException('Daily marketing cap reached');
80	            }
81	
82	            $start = (string) Config::get('security.messaging.quiet_hours_start', '21:00');
83	            $end = (string) Config::get('security.messaging.quiet_hours_end', '08:00');
84	            $now = $this->hourMinute();
85	            if ($now >= $start || $now < $end) {
86	                throw new \RuntimeException('Quiet hours active (21:00-08:00)');
87	            }
88	        }
89	
90	        $nowString = $this->nowString();
91	
92	        $id = (int) Db::name('message_center')->insertGetId([
