105	    public function recipientInScope(array $recipient, array $scopes = [], array $authUser = []): bool
106	    {
107	        $store = array_map('strval', $scopes['store'] ?? []);
108	        $warehouse = array_map('strval', $scopes['warehouse'] ?? []);
109	        $department = array_map('strval', $scopes['department'] ?? []);
110	
111	        $recipientStore = (string) ($recipient['store_id'] ?? '');
112	        $recipientWarehouse = (string) ($recipient['warehouse_id'] ?? '');
113	        $recipientDepartment = (string) ($recipient['department_id'] ?? '');
114	
115	        if ($store !== [] && !in_array($recipientStore, $store, true)) {
116	            return false;
117	        }
118	        if ($warehouse !== [] && !in_array($recipientWarehouse, $warehouse, true)) {
119	            return false;
120	        }
121	        if ($department !== [] && !in_array($recipientDepartment, $department, true)) {
122	            return false;
123	        }
124	
125	        if ($store === [] && !empty($authUser['store_id']) && $recipientStore !== (string) $authUser['store_id']) {
126	            return false;
127	        }
128	        if ($warehouse === [] && !empty($authUser['warehouse_id']) && $recipientWarehouse !== (string) $authUser['warehouse_id']) {
