4	namespace app\service;
5	
6	use app\exception\ForbiddenException;
7	use app\exception\NotFoundException;
8	use app\exception\ValidationException;
9	use app\infrastructure\filesystem\LocalFileStorageAdapter;
10	use app\repository\FileRepository;
11	use think\facade\Config;
12	use think\facade\Log;
13	
14	final class FileService
15	{
16	    public function __construct(
17	        private readonly FileRepository $fileRepository,
18	        private readonly LocalFileStorageAdapter $fileStorageAdapter
19	    ) {
20	    }
21	
22	    public function uploadBase64(array $payload): array
23	    {
24	        $filename = (string) ($payload['filename'] ?? 'upload.bin');
25	        $mimeType = (string) ($payload['mime_type'] ?? 'application/octet-stream');
26	        $maxSize = (int) Config::get('security.files.max_size_bytes', 5242880);
27	        $allowed = Config::get('security.files.allowed_mime_types', []);
28	
29	        if (!in_array($mimeType, $allowed, true)) {
30	            throw new ValidationException('Unsupported file type');
31	        }
32	
33	        $stored = $this->fileStorageAdapter->saveBase64($payload['filename'], $payload['content_base64']);
34	        if ((int) $stored['size_bytes'] > $maxSize) {
35	            $this->fileStorageAdapter->delete((string) $stored['storage_path']);
36	            throw new ValidationException('File too large');
37	        }
38	
39	        $bytes = (string) ($stored['bytes'] ?? '');
40	        $magicVerified = $this->verifyMagicBytes($mimeType, $bytes);
41	        if (!$magicVerified) {
42	            throw new ValidationException('Magic-byte verification failed');
43	        }
44	
45	        $watermarked = (bool) ($payload['watermark'] ?? false);
46	        if ($watermarked) {
47	            if (!in_array($mimeType, ['image/png', 'image/jpeg'], true)) {
48	                throw new ValidationException('Watermarking is only supported for PNG/JPEG images');
49	            }
50	            $bytes = $this->renderImageWatermark($mimeType, $bytes);
51	            if (!$this->verifyMagicBytes($mimeType, $bytes)) {
52	                throw new ValidationException('Watermarked image failed magic-byte verification');
53	            }
54	            file_put_contents($this->fileStorageAdapter->absolutePath($stored['storage_path']), $bytes);
55	            $stored['size_bytes'] = strlen($bytes);
56	            if ((int) $stored['size_bytes'] > $maxSize) {
57	                $this->fileStorageAdapter->delete((string) $stored['storage_path']);
58	                throw new ValidationException('File too large');
59	            }
60	        }
61	
62	        $sha256 = hash('sha256', $bytes);
63	        $id = $this->fileRepository->addAttachment([
64	            'owner_type' => $payload['owner_type'] ?? 'general',
65	            'owner_id' => (int) ($payload['owner_id'] ?? 0),
66	            'filename' => $filename,
67	            'mime_type' => $mimeType,
68	            'storage_path' => $stored['storage_path'],
69	            'size_bytes' => $stored['size_bytes'],
70	            'sha256' => $sha256,
71	            'magic_verified' => $magicVerified ? 1 : 0,
72	            'watermarked' => $watermarked ? 1 : 0,
73	        ]);
74	
75	        Log::info('files.upload_base64.stored', ['attachment_id' => $id, 'owner_type' => $payload['owner_type'] ?? 'general', 'owner_id' => (int) ($payload['owner_id'] ?? 0), 'mime_type' => $mimeType, 'size_bytes' => (int) $stored['size_bytes']]);
76	
77	        return ['id' => $id, 'storage_path' => $stored['storage_path'], 'sha256' => $sha256];
78	    }
79	
80	    public function list(array $scopes = [], array $authUser = []): array
81	    {
82	        $items = $this->fileRepository->listAttachmentsScoped($scopes, $authUser);
83	        foreach ($items as &$item) {
84	            $item['sha256'] = $this->maskHash((string) ($item['sha256'] ?? ''));
85	        }
86	        return $items;
87	    }
88	
89	    public function createSignedDownloadUrl(int $attachmentId, array $scopes = [], array $authUser = []): array
90	    {
91	        $attachment = $this->fileRepository->byId($attachmentId);
92	        if (!$attachment) {
93	            throw new NotFoundException('Attachment not found');
94	        }
95	        if (!$this->fileRepository->attachmentInScope($attachmentId, $scopes, $authUser)) {
96	            throw new ForbiddenException('Forbidden');
97	        }
98	
99	        $token = hash('sha256', $attachment['id'] . '|' . random_bytes(12) . '|' . date('c'));
100	        $expireAt = date('Y-m-d H:i:s', time() + (int) Config::get('security.files.download_url_ttl_seconds', 300));
101	        $this->fileRepository->updateSignedToken($attachmentId, $token, $expireAt);
102	
103	        return [
104	            'attachment_id' => $attachmentId,
105	            'download_url' => '/api/v1/files/download/' . $attachmentId . '?token=' . $token,
106	            'expire_at' => $expireAt,
107	        ];
108	    }
109	
110	    public function validateDownloadToken(int $attachmentId, string $token, array $scopes = [], array $authUser = []): array
111	    {
112	        $attachment = $this->fileRepository->byId($attachmentId);
113	        if (!$attachment) {
114	            throw new NotFoundException('Attachment not found');
115	        }
116	        if (!$this->fileRepository->attachmentInScope($attachmentId, $scopes, $authUser)) {
117	            throw new ForbiddenException('Forbidden');
118	        }
119	
120	        if ((string) ($attachment['hotlink_token'] ?? '') !== $token) {
121	            throw new ForbiddenException('Invalid hotlink token');
122	        }
123	
124	        if (strtotime((string) ($attachment['signed_url_expire_at'] ?? '1970-01-01 00:00:00')) <= time()) {
125	            throw new ForbiddenException('Signed URL expired');
126	        }
127	
128	        return [
129	            'filename' => $attachment['filename'],
130	            'mime_type' => $attachment['mime_type'],
131	            'content_base64' => base64_encode($this->fileStorageAdapter->read((string) $attachment['storage_path'])),
132	        ];
133	    }
134	
135	    public function cleanupLifecycle(array $scopes = [], array $authUser = []): array
136	    {
137	        $retentionDays = (int) Config::get('security.files.retention_days', 180);
138	        $expired = $this->fileRepository->expiredAttachments($retentionDays, $scopes, $authUser);
139	
140	        $deletedRecords = 0;
141	        $deletedFiles = 0;
142	        $missingFiles = 0;
143	        $errors = 0;
144	
145	        foreach ($expired as $row) {
146	            $id = (int) ($row['id'] ?? 0);
147	            $storagePath = (string) ($row['storage_path'] ?? '');
148	            if ($id < 1 || $storagePath === '') {
149	                continue;
150	            }
151	
152	            try {
153	                $absolutePath = $this->fileStorageAdapter->absolutePath($storagePath);
154	                if (is_file($absolutePath)) {
155	                    if ($this->fileStorageAdapter->delete($storagePath)) {
156	                        $deletedFiles++;
157	                    } else {
158	                        throw new \RuntimeException('failed to delete file path: ' . $storagePath);
159	                    }
160	                } else {
161	                    $missingFiles++;
162	                    Log::info('files.cleanup.missing_file', ['attachment_id' => $id, 'storage_path' => $storagePath]);
163	                }
164	
165	                if ($this->fileRepository->deleteAttachment($id)) {
166	                    $deletedRecords++;
167	                }
168	            } catch (\Throwable $e) {
169	                $errors++;
170	                Log::info('files.cleanup.error', ['attachment_id' => $id, 'storage_path' => $storagePath, 'error' => $e->getMessage()]);
171	            }
172	        }
173	
174	        return [
175	            'deleted_records' => $deletedRecords,
176	            'deleted_files' => $deletedFiles,
177	            'missing_files' => $missingFiles,
178	            'errors' => $errors,
179	            'retention_days' => $retentionDays,
180	        ];
181	    }
182	
183	    private function verifyMagicBytes(string $mimeType, string $bytes): bool
184	    {
185	        $prefix = substr($bytes, 0, 4);
186	        if ($mimeType === 'application/pdf') {
187	            return str_starts_with($bytes, '%PDF');
188	        }
189	
190	        if ($mimeType === 'image/png') {
191	            return $prefix === "\x89PNG";
192	        }
193	
194	        if ($mimeType === 'image/jpeg') {
195	            return str_starts_with($bytes, "\xFF\xD8\xFF");
196	        }
197	
198	        if ($mimeType === 'text/csv') {
199	            return mb_check_encoding($bytes, 'UTF-8');
200	        }
201	
202	        return false;
203	    }
204	
205	    private function maskHash(string $hash): string
206	    {
207	        if ($hash === '' || strlen($hash) < 12) {
208	            return $hash;
209	        }
210	
211	        return substr($hash, 0, 6) . str_repeat('*', 52) . substr($hash, -6);
212	    }
213	
214	    private function renderImageWatermark(string $mimeType, string $bytes): string
215	    {
216	        if (!function_exists('imagecreatefromstring') || !function_exists('imagestring')) {
217	            throw new ValidationException('Image watermarking requires GD extension support');
218	        }
219	
220	        $image = imagecreatefromstring($bytes);
221	        if ($image === false) {
222	            throw new ValidationException('Invalid image payload for watermark rendering');
223	        }
224	
225	        $width = imagesx($image);
226	        $height = imagesy($image);
227	        $label = 'PantryPilot';
228	        $font = 3;
229	        $textWidth = imagefontwidth($font) * strlen($label);
230	        $textHeight = imagefontheight($font);
231	        $x = max(5, $width - $textWidth - 8);
232	        $y = max(5, $height - $textHeight - 8);
233	
234	        if (function_exists('imagealphablending')) {
235	            imagealphablending($image, true);
236	        }
237	        $color = imagecolorallocatealpha($image, 255, 255, 255, 70);
238	        imagestring($image, $font, $x, $y, $label, $color);
239	
240	        ob_start();
241	        $written = false;
242	        if ($mimeType === 'image/png') {
243	            if (function_exists('imagesavealpha')) {
244	                imagesavealpha($image, true);
245	            }
246	            $written = imagepng($image);
247	        } else {
248	            $written = imagejpeg($image, null, 90);
249	        }
250	        $rendered = (string) ob_get_clean();
251	        imagedestroy($image);
252	
253	        if (!$written || $rendered === '') {
254	            throw new ValidationException('Watermark rendering failed');
255	        }
256	
257	        return $rendered;
258	    }
259	}
