116	    public function slotCapacity(int $pickupPointId, string $slotStart, string $slotEnd): array
117	    {
118	        $slot = Db::name('pickup_slots')
119	            ->where('pickup_point_id', $pickupPointId)
120	            ->where('slot_start', $slotStart)
121	            ->where('slot_end', $slotEnd)
122	            ->find();
123	
124	        if (!$slot) {
125	            $point = Db::name('pickup_points')->where('id', $pickupPointId)->find();
126	            $capacity = (int) ($point['slot_size'] ?? 0);
127	            return ['capacity' => $capacity, 'reserved' => 0, 'remaining' => $capacity];
128	        }
129	
130	        $capacity = (int) $slot['capacity'];
131	        $reserved = (int) $slot['reserved_count'];
132	        return ['capacity' => $capacity, 'reserved' => $reserved, 'remaining' => max(0, $capacity - $reserved)];
133	    }
