154	    public function reserveSlotAtomic(int $pickupPointId, string $slotStart, string $slotEnd, int $quantity): array
155	    {
156	        $slot = Db::name('pickup_slots')
157	            ->where('pickup_point_id', $pickupPointId)
158	            ->where('slot_start', $slotStart)
159	            ->where('slot_end', $slotEnd)
160	            ->lock(true)
161	            ->find();
162	
163	        if (!$slot) {
164	            throw new \RuntimeException('Slot not found');
165	        }
166	
167	        $capacity = (int) $slot['capacity'];
168	        $reserved = (int) $slot['reserved_count'];
169	        $remaining = $capacity - $reserved;
170	        if ($remaining < $quantity) {
171	            throw new \RuntimeException('Slot capacity is not enough');
172	        }
173	
174	        Db::name('pickup_slots')->where('id', $slot['id'])->update([
175	            'reserved_count' => $reserved + $quantity,
176	            'updated_at' => date('Y-m-d H:i:s'),
177	        ]);
178	
179	        return [
180	            'capacity' => $capacity,
181	            'reserved' => $reserved + $quantity,
182	            'remaining' => $capacity - ($reserved + $quantity),
183	        ];
184	    }
