        ->execute([$code, 1, 1, 1, $slot, $slot, date('Y-m-d H:i:s', strtotime($slot) + 1800), 1, 'pending', '1', '1', '1', date('Y-m-d H:i:s'), date('Y-m-d H:i:s')]);
    $scopedBookingId = (int) $pdo->lastInsertId();

    $gwOrder = api('POST', '/api/v1/payments/gateway/orders', [
