35	    public function anomalyMetrics(array $scopes = [], array $authUser = []): array
36	    {
37	        $recentQ = Db::name('bookings')->alias('b')->whereTime('created_at', '>=', date('Y-m-d H:i:s', strtotime('-7 days')));
38	        $this->applyDataScopes($recentQ, 'b', $scopes, $authUser);
39	        $recentBookings = (int) $recentQ->count();
40	        $oversellQuery = Db::name('pickup_slots')->alias('ps')
41	            ->join('bookings b', 'b.pickup_point_id = ps.pickup_point_id AND b.slot_start = ps.slot_start AND b.slot_end = ps.slot_end')
42	            ->whereRaw('ps.reserved_count > ps.capacity');
43	        $this->applyDataScopes($oversellQuery, 'b', $scopes, $authUser);
44	        $oversell = (int) $oversellQuery->count('DISTINCT ps.id');
45	
46	        $refundQ = Db::name('payments')->alias('p')->where('status', 'refunded')->whereTime('created_at', '>=', date('Y-m-d H:i:s', strtotime('-7 days')));
47	        $paymentQ = Db::name('payments')->alias('p')->whereTime('created_at', '>=', date('Y-m-d H:i:s', strtotime('-7 days')));
48	        $this->applyDataScopes($refundQ, 'p', $scopes, $authUser);
49	        $this->applyDataScopes($paymentQ, 'p', $scopes, $authUser);
50	        $refunds = (int) $refundQ->count();
51	        $paymentTotal = (int) $paymentQ->count();
52	        $refundRate = $paymentTotal > 0 ? round(($refunds / $paymentTotal) * 100, 2) : 0.0;
53	
54	        $stockoutsQ = Db::name('stock_snapshots')->alias('s')->where('s.qty', '<=', 0)->whereDay('s.snapshot_date', date('Y-m-d'));
55	        $stockTotalQ = Db::name('stock_snapshots')->alias('s')->whereDay('s.snapshot_date', date('Y-m-d'));
56	        $this->applyDataScopes($stockoutsQ, 's', $scopes, $authUser);
57	        $this->applyDataScopes($stockTotalQ, 's', $scopes, $authUser);
58	        $stockouts = (int) $stockoutsQ->count();
