60	        $stockoutRate = $stockTotal > 0 ? round(($stockouts / $stockTotal) * 100, 2) : 0.0;
61	
62	        $alerts = [];
63	        if ($oversell > 0) {
64	            $alerts[] = ['type' => 'oversell', 'severity' => 'high', 'count' => $oversell];
