76	                'severity' => $alert['severity'],
77	                'payload' => json_encode($alert, JSON_UNESCAPED_UNICODE),
78	                'created_at' => date('Y-m-d H:i:s'),
79	            ]);
80	        }
81	
82	        return [
83	            'recent_bookings_7d' => $recentBookings,
84	            'oversell_count' => $oversell,
85	            'refund_rate_7d' => $refundRate,
86	            'stockout_rate_today' => $stockoutRate,
87	            'alerts' => $alerts,
88	        ];
89	    }
