22	    public function uploadBase64(array $payload): array
23	    {
24	        $filename = (string) ($payload['filename'] ?? 'upload.bin');
25	        $mimeType = (string) ($payload['mime_type'] ?? 'application/octet-stream');
26	        $maxSize = (int) Config::get('security.files.max_size_bytes', 5242880);
27	        $allowed = Config::get('security.files.allowed_mime_types', []);
28	
29	        if (!in_array($mimeType, $allowed, true)) {
30	            throw new ValidationException('Unsupported file type');
31	        }
32	
33	        $stored = $this->fileStorageAdapter->saveBase64($payload['filename'], $payload['content_base64']);
34	        if ((int) $stored['size_bytes'] > $maxSize) {
35	            $this->fileStorageAdapter->delete((string) $stored['storage_path']);
36	            throw new ValidationException('File too large');
37	        }
38	
39	        $bytes = (string) ($stored['bytes'] ?? '');
40	        $magicVerified = $this->verifyMagicBytes($mimeType, $bytes);
41	        if (!$magicVerified) {
42	            throw new ValidationException('Magic-byte verification failed');
43	        }
44	
45	        $watermarked = (bool) ($payload['watermark'] ?? false);
46	        if ($watermarked) {
47	            if (!in_array($mimeType, ['image/png', 'image/jpeg'], true)) {
48	                throw new ValidationException('Watermarking is only supported for PNG/JPEG images');
49	            }
50	            $bytes = $this->renderImageWatermark($mimeType, $bytes);
51	            if (!$this->verifyMagicBytes($mimeType, $bytes)) {
52	                throw new ValidationException('Watermarked image failed magic-byte verification');
53	            }
54	            file_put_contents($this->fileStorageAdapter->absolutePath($stored['storage_path']), $bytes);
55	            $stored['size_bytes'] = strlen($bytes);
56	            if ((int) $stored['size_bytes'] > $maxSize) {
57	                $this->fileStorageAdapter->delete((string) $stored['storage_path']);
58	                throw new ValidationException('File too large');
59	            }
60	        }
61	
62	        $sha256 = hash('sha256', $bytes);
63	        $id = $this->fileRepository->addAttachment([
64	            'owner_type' => $payload['owner_type'] ?? 'general',
65	            'owner_id' => (int) ($payload['owner_id'] ?? 0),
66	            'filename' => $filename,
67	            'mime_type' => $mimeType,
68	            'storage_path' => $stored['storage_path'],
69	            'size_bytes' => $stored['size_bytes'],
70	            'sha256' => $sha256,
71	            'magic_verified' => $magicVerified ? 1 : 0,
72	            'watermarked' => $watermarked ? 1 : 0,
73	        ]);
74	
75	        Log::info('files.upload_base64.stored', ['attachment_id' => $id, 'owner_type' => $payload['owner_type'] ?? 'general', 'owner_id' => (int) ($payload['owner_id'] ?? 0), 'mime_type' => $mimeType, 'size_bytes' => (int) $stored['size_bytes']]);
76	
77	        return ['id' => $id, 'storage_path' => $stored['storage_path'], 'sha256' => $sha256];
78	    }
