1	<?php
2	declare(strict_types=1);
3	
4	namespace app\service;
5	
6	use app\domain\identity\LoginLockPolicy;
7	use app\domain\identity\PasswordPolicy;
8	use app\repository\AuthSessionRepository;
9	use app\repository\IdentityRepository;
10	use think\facade\Log;
11	
12	final class IdentityService
13	{
14	    public function __construct(
15	        private readonly IdentityRepository $identityRepository,
16	        private readonly PasswordPolicy $passwordPolicy,
17	        private readonly LoginLockPolicy $loginLockPolicy,
18	        private readonly AuthTokenService $authTokenService,
19	        private readonly AuthSessionRepository $authSessionRepository,
20	        private readonly CryptoService $cryptoService
21	    )
22	    {
23	    }
24	
25	    public function register(array $payload): array
26	    {
27	        $username = (string) ($payload['username'] ?? '');
28	        if (!preg_match('/^[a-zA-Z0-9_]{3,50}$/', $username)) {
29	            throw new \InvalidArgumentException('Username must be 3-50 chars, letters/numbers/underscore only');
30	        }
31	
32	        $exists = $this->identityRepository->findByUsername($payload['username']);
33	        if ($exists) {
34	            throw new \InvalidArgumentException('Username already exists');
35	        }
36	
37	        $this->passwordPolicy->assertValid((string) ($payload['password'] ?? ''));
38	
39	        $id = $this->identityRepository->createUser([
40	            'username' => $payload['username'],
41	            'display_name' => $payload['display_name'] ?? $payload['username'],
42	            'password_hash' => password_hash($payload['password'], PASSWORD_BCRYPT),
43	            'role' => 'customer',
44	            'phone_enc' => $this->cryptoService->encrypt((string) ($payload['phone'] ?? '')),
45	            'address_enc' => $this->cryptoService->encrypt((string) ($payload['address'] ?? '')),
46	        ]);
47	
48	        return ['id' => $id];
49	    }
50	
51	    public function login(string $username, string $password, string $ip = '', string $userAgent = ''): array
52	    {
53	        $user = $this->identityRepository->findByUsername($username);
54	
55	        if (!$user) {
56	            Log::info('identity.login.failed', ['username' => $username, 'reason' => 'user_not_found', 'ip' => $ip]);
57	            throw new \RuntimeException('Invalid credentials');
58	        }
59	
60	        if ((int) ($user['account_enabled'] ?? 1) !== 1) {
61	            Log::info('identity.login.failed', ['user_id' => (int) $user['id'], 'username' => $username, 'reason' => 'account_disabled', 'ip' => $ip]);
62	            throw new \RuntimeException('Account disabled');
63	        }
64	
65	        try {
66	            $this->loginLockPolicy->assertNotLocked($user['locked_until'] ?? null);
67	        } catch (\RuntimeException $e) {
68	            Log::info('identity.login.failed', ['user_id' => (int) $user['id'], 'username' => $username, 'reason' => 'locked', 'locked_until' => $user['locked_until'] ?? null, 'ip' => $ip]);
69	            throw $e;
70	        }
71	
72	        if (!password_verify($password, $user['password_hash'])) {
73	            $attempts = $this->loginLockPolicy->nextAttempts((int) ($user['failed_login_attempts'] ?? 0));
74	            $lockedUntil = $this->loginLockPolicy->shouldLock($attempts) ? $this->loginLockPolicy->lockedUntil() : null;
75	            $this->identityRepository->incrementFailedLogin((int) $user['id'], $attempts, $lockedUntil);
76	            Log::info('identity.login.failed', ['user_id' => (int) $user['id'], 'username' => $username, 'reason' => 'bad_password', 'attempts' => $attempts, 'locked_until' => $lockedUntil, 'ip' => $ip]);
77	            throw new \RuntimeException('Invalid credentials');
78	        }
79	
80	        $this->identityRepository->clearFailedLogins((int) $user['id']);
81	
82	        $token = $this->authTokenService->issueToken();
83	        $this->authSessionRepository->create(
84	            (int) $user['id'],
85	            $this->authTokenService->hashToken($token),
86	            $ip,
87	            $userAgent,
88	            $this->authTokenService->expirationDateTime()
89	        );
90	
91	        Log::info('identity.login.success', ['user_id' => (int) $user['id'], 'username' => $username, 'ip' => $ip]);
92	
93	        return [
94	            'token' => $token,
95	            'user' => [
96	                'id' => $user['id'],
97	                'username' => $user['username'],
98	                'display_name' => $user['display_name'],
99	                'role' => $user['role'],
100	            ],
101	        ];
102	    }
103	
104	    public function userByToken(string $rawToken): ?array
105	    {
106	        if ($rawToken === '') {
107	            return null;
108	        }
109	
110	        $session = $this->authSessionRepository->findActiveByTokenHash($this->authTokenService->hashToken($rawToken));
111	        if (!$session) {
112	            return null;
113	        }
114	
115	        $this->authSessionRepository->touch((int) $session['id']);
116	        $user = $this->identityRepository->findById((int) $session['user_id']);
117	        if (!$user) {
118	            return null;
119	        }
120	        if ((int) ($user['account_enabled'] ?? 1) !== 1) {
121	            return null;
122	        }
123	
124	        return [
125	            'id' => (int) $user['id'],
126	            'username' => (string) $user['username'],
127	            'display_name' => (string) $user['display_name'],
128	            'role' => (string) $user['role'],
129	            'store_id' => (string) ($user['store_id'] ?? ''),
130	            'warehouse_id' => (string) ($user['warehouse_id'] ?? ''),
131	            'department_id' => (string) ($user['department_id'] ?? ''),
132	        ];
133	    }
134	}
