7	
8	final class AuthorizationRepository
9	{
10	    public function hasPermission(int $userId, string $resourceCode, string $permissionCode): bool
11	    {
12	        $count = Db::name('user_roles')->alias('ur')
13	            ->join('role_permission_resources rpr', 'rpr.role_id = ur.role_id')
14	            ->join('permissions p', 'p.id = rpr.permission_id')
15	            ->join('resources r', 'r.id = rpr.resource_id')
16	            ->where('ur.user_id', $userId)
17	            ->where('p.code', $permissionCode)
18	            ->where('r.code', $resourceCode)
19	            ->count();
20	
21	        return $count > 0;
22	    }
23	
24	    public function scopesByUser(int $userId): array
25	    {
26	        $rows = Db::name('user_data_scopes')->where('user_id', $userId)->select()->toArray();
27	        $scopes = [
28	            'store' => [],
29	            'warehouse' => [],
30	            'department' => [],
31	        ];
32	
33	        foreach ($rows as $row) {
34	            $type = (string) $row['scope_type'];
35	            if (!isset($scopes[$type])) {
36	                continue;
37	            }
38	            $scopes[$type][] = (string) $row['scope_value'];
39	        }
40	
41	        return $scopes;
42	    }
43	}
