32	        }
33	
34	        $cipher = (string) Config::get('security.crypto.cipher');
35	        $key = substr(hash('sha256', (string) Config::get('security.crypto.key'), true), 0, 32);
36	
37	        $raw = base64_decode($encrypted, true);
