18	    public function handle(Request $request, Closure $next)
19	    {
20	        $routeKey = strtoupper($request->method()) . ':' . trim($request->pathinfo(), '/');
21	        if ($routeKey === 'GET:') {
22	            $routeKey = 'GET:/';
23	        }
24	
25	        $rules = Config::get('acl.permissions', []);
26	        $matchedKey = $this->matchRoute($routeKey, array_keys($rules));
27	        if ($matchedKey === null) {
28	            return $next($request);
29	        }
30	
31	        $authUser = $request->middleware('auth_user');
32	        if (!$authUser) {
33	            return JsonResponse::error('Unauthorized', 401);
34	        }
35	
36	        $required = $rules[$matchedKey];
37	        $can = $this->authorizationService->can(
38	            (int) $authUser['id'],
39	            (string) $required['resource'],
40	            (string) $required['permission']
41	        );
42	
43	        if (!$can) {
44	            return JsonResponse::error('Forbidden', 403);
45	        }
46	
47	        $request->withMiddleware([
48	            'data_scopes' => $this->authorizationService->dataScopes((int) $authUser['id']),
49	        ]);
50	
51	        return $next($request);
52	    }
