54	    private function matchRoute(string $routeKey, array $patterns): ?string
55	    {
56	        if (in_array($routeKey, $patterns, true)) {
57	            return $routeKey;
58	        }
59	
60	        foreach ($patterns as $pattern) {
61	            if (str_contains($pattern, '*') && fnmatch($pattern, $routeKey)) {
62	                return $pattern;
63	            }
64	        }
65	
66	        return null;
67	    }
68	}
