        ->execute(['Slot Scope Test', 'Nowhere', 3, 1, '888', '888', '888', date('Y-m-d H:i:s')]);
    $foreignId = (int) $pdo->lastInsertId();
    $slotStart = date('Y-m-d H:i:s', strtotime('+5 day 10:00'));
