182	    public function dailyReconciliation(string $date, array $scopes = [], array $authUser = []): array
183	    {
184	        $gatewayOrders = $this->paymentRepository->paidGatewayOrdersByDate($date, $scopes, $authUser);
185	        $payments = $this->paymentRepository->paymentsByDate($date, $scopes, $authUser);
186	        $paymentMap = [];
187	        foreach ($payments as $p) {
188	            $paymentMap[(int) $p['booking_id']] = true;
189	        }
190	
191	        $batchRef = 'DREC-' . date('Ymd') . '-' . strtoupper(bin2hex(random_bytes(2)));
192	        $issues = 0;
193	        $expected = 0.0;
194	        $actual = 0.0;
195	
196	        foreach ($gatewayOrders as $order) {
197	            $expected += (float) $order['amount'];
198	            if (isset($paymentMap[(int) $order['booking_id']])) {
199	                $actual += (float) $order['amount'];
200	            } else {
201	                $issues++;
202	                $this->paymentRepository->addReconciliationIssue([
203	                    'batch_ref' => $batchRef,
204	                    'gateway_order_ref' => $order['order_ref'],
205	                    'issue_type' => 'missed_order',
206	                ]);
207	            }
208	        }
209	
210	        $rec = $this->reconcile([
211	            'batch_ref' => $batchRef,
212	            'period_start' => $date,
213	            'period_end' => $date,
214	            'expected_total' => $expected,
215	            'actual_total' => $actual,
216	            'status' => $issues > 0 ? 'abnormal' : 'open',
217	        ]);
218	
219	        Log::info('payments.daily_reconciliation.completed', ['date' => $date, 'batch_ref' => $rec['batch_ref'], 'issues' => $issues, 'variance' => $rec['variance']]);
220	
221	        return ['batch_ref' => $rec['batch_ref'], 'issues' => $issues, 'variance' => $rec['variance']];

